import { headers } from "next/headers";
import { listEnrollTokens } from "@/lib/queries";
import EnrollClient from "./EnrollClient";

export const dynamic = "force-dynamic";

export default async function EnrollPage() {
  const tokens = await listEnrollTokens();
  const h = await headers();
  const host = h.get("host") ?? "your-hub:3001";
  const proto = h.get("x-forwarded-proto") ?? "http";
  const hubUrl = `${proto}://${host}`;

  return (
    <>
      <h1>Enroll an instance</h1>

      <div className="card" style={{ marginBottom: 16 }}>
        <h2 style={{ marginTop: 0 }}>1. Generate an enrollment token</h2>
        <EnrollClient />
      </div>

      <div className="card" style={{ marginBottom: 16 }}>
        <h2 style={{ marginTop: 0 }}>2. Run on the Linux host</h2>
        <p className="muted" style={{ marginTop: 0 }}>
          One-liner — pulls the prebuilt agent binary from this hub, installs a
          systemd unit, and starts it. No Bun or other runtime needed on the
          host.
        </p>
        <pre>{`curl -fsSL ${hubUrl}/install.sh | sudo HUB_URL=${hubUrl} ENROLL_TOKEN=<token> bash`}</pre>
        <p className="muted">
          Or pull the binary directly:{" "}
          <code>{`${hubUrl}/api/install/agent/x64`}</code> /{" "}
          <code>{`${hubUrl}/api/install/agent/arm64`}</code>
        </p>
      </div>

      <h2>Existing enrollment tokens</h2>
      <div className="card" style={{ padding: 0 }}>
        <table>
          <thead><tr><th>Token</th><th>Created</th></tr></thead>
          <tbody>
            {tokens.length === 0 && (
              <tr><td colSpan={2} className="empty">No tokens yet.</td></tr>
            )}
            {tokens.map((t) => (
              <tr key={t.token}>
                <td style={{ fontFamily: "ui-monospace, monospace" }}>{t.token}</td>
                <td className="muted">{new Date(t.createdAt).toLocaleString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </>
  );
}
